-- De-duplicated mapping (case-insensitive unique)
START TRANSACTION;

CREATE TEMPORARY TABLE _unit_map (word VARCHAR(128), new_unit INT, INDEX(word));


UPDATE word w JOIN _unit_map m ON w.word = m.word SET w.unit = m.new_unit;

DROP TEMPORARY TABLE _unit_map;

COMMIT;

SELECT unit, COUNT(*) as cnt FROM word GROUP BY unit ORDER BY unit;